#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    for(int i=0;i<T;++i){
        int op; if(scanf("%d", &op)!=1) break;
        if(op==111){
            long long a,b; scanf("%lld %lld", &a, &b);
            printf("%lld\n", a+b);
        } else if(op==222){
            long long a,b; scanf("%lld %lld", &a, &b);
            printf("%lld\n", a-b);
        } else if(op==333){
            // no output
        } else {
            printf("Operation does not exist - please provide the correct input\n");
        }
    }
    return 0;
}

